    secondary_thread.start()
    time.sleep(1)

    tests = [
        ("Non-watch mode", test_non_watch_mode),
        ("Watch mode primary", test_watch_mode_primary),
        ("Priority", test_priority),
        ("Arg override", test_arg_override),
