class _FloatEncoder(json.JSONEncoder):
    """Custom JSON encoder that formats floats with exactly 6 decimal places."""

    def default(self, o):
        return super().default(o)

    def encode(self, o):
        return super().encode(o)

    def iterencode(self, o, _one_shot=False):
        for chunk in super().iterencode(o, _one_shot):
            yield self._format_floats(chunk)

    def _format_floats(self, s):
        # Match floats in JSON output - they appear as standalone numbers
        # Pattern: optional minus, digits, decimal point, digits, not followed by
        # characters that would indicate it's part of a string or another number
        return re.sub(
            r'(?<![0-9.])"-?\d+\.\d+"(?![0-9.])',
            lambda m: '"' + f"{float(m.group()[1:-1]):.6f}" + '"',
            s
        )

